package org.jsoup.parser;

import org.jsoup.nodes.Document;
import org.jsoup.nodes.DocumentType;
import org.jsoup.nodes.Element;

import static org.jsoup.internal.StringUtil.inSorted;
import static org.jsoup.parser.HtmlTreeBuilderStateConstants.*;

/**
 * Helper holder for head-related processing methods. Methods moved out of the
 * HtmlTreeBuilderState enum to keep head-related logic modular.
 */
public final class HtmlTreeBuilderStateHeadHandlers {

    private HtmlTreeBuilderStateHeadHandlers() {}

    public static boolean processInitial(Token t, HtmlTreeBuilder tb) {
        if (HtmlTreeBuilderStateHelper.isWhitespace(t)) {
            return true; // ignore whitespace until we get the first content
        } else if (t.isComment()) {
            tb.insertCommentNode(t.asComment());
        } else if (t.isDoctype()) {
            // todo: parse error check on expected doctypes
            Token.Doctype d = t.asDoctype();
            DocumentType doctype = new DocumentType(
                tb.settings.normalizeTag(d.getName()), d.getPublicIdentifier(), d.getSystemIdentifier());
            doctype.setPubSysKey(d.getPubSysKey());
            tb.getDocument().appendChild(doctype);
            tb.onNodeInserted(doctype);
            // todo: quirk state check on more doctype ids, if deemed useful (most are ancient legacy and presumably irrelevant)
            if (d.isForceQuirks() || !doctype.name().equals("html") || doctype.publicId().equalsIgnoreCase("HTML"))
                tb.getDocument().quirksMode(Document.QuirksMode.quirks);
            tb.transition(HtmlTreeBuilderState.BeforeHtml);
        } else {
            // todo: check not iframe srcdoc
            tb.getDocument().quirksMode(Document.QuirksMode.quirks); // missing doctype
            tb.transition(HtmlTreeBuilderState.BeforeHtml);
            return tb.process(t); // re-process token
        }
        return true;
    }

    public static boolean processBeforeHtml(Token t, HtmlTreeBuilder tb) {
        if (t.isDoctype()) {
            tb.error(HtmlTreeBuilderState.BeforeHtml);
            return false;
        } else if (t.isComment()) {
            tb.insertCommentNode(t.asComment());
        } else if (HtmlTreeBuilderStateHelper.isWhitespace(t)) {
            tb.insertCharacterNode(t.asCharacter()); // out of spec - include whitespace
        } else if (t.isStartTag() && t.asStartTag().normalName().equals("html")) {
            tb.insertElementFor(t.asStartTag());
            tb.transition(HtmlTreeBuilderState.BeforeHead);
        } else if (t.isEndTag() && (inSorted(t.asEndTag().normalName(), BeforeHtmlToHead))) {
            return anythingElseBeforeHtml(t, tb);
        } else if (t.isEndTag()) {
            tb.error(HtmlTreeBuilderState.BeforeHtml);
            return false;
        } else {
            return anythingElseBeforeHtml(t, tb);
        }
        return true;
    }

    private static boolean anythingElseBeforeHtml(Token t, HtmlTreeBuilder tb) {
        tb.processStartTag("html");
        tb.transition(HtmlTreeBuilderState.BeforeHead);
        return tb.process(t);
    }

    public static boolean processBeforeHead(Token t, HtmlTreeBuilder tb) {
        if (HtmlTreeBuilderStateHelper.isWhitespace(t)) {
            tb.insertCharacterNode(t.asCharacter()); // out of spec - include whitespace
        } else if (t.isComment()) {
            tb.insertCommentNode(t.asComment());
        } else if (t.isDoctype()) {
            tb.error(HtmlTreeBuilderState.BeforeHead);
            return false;
        } else if (t.isStartTag() && t.asStartTag().normalName().equals("html")) {
            return HtmlTreeBuilderState.InBody.process(t, tb); // does not transition
        } else if (t.isStartTag() && t.asStartTag().normalName().equals("head")) {
            Element head = tb.insertElementFor(t.asStartTag());
            tb.setHeadElement(head);
            tb.transition(HtmlTreeBuilderState.InHead);
        } else if (t.isEndTag() && (inSorted(t.asEndTag().normalName(), BeforeHtmlToHead))) {
            tb.processStartTag("head");
            return tb.process(t);
        } else if (t.isEndTag()) {
            tb.error(HtmlTreeBuilderState.BeforeHead);
            return false;
        } else {
            tb.processStartTag("head");
            return tb.process(t);
        }
        return true;
    }

    public static boolean processInHead(Token t, HtmlTreeBuilder tb) {
        if (HtmlTreeBuilderStateHelper.isWhitespace(t)) {
            tb.insertCharacterNode(t.asCharacter()); // out of spec - include whitespace
            return true;
        }
        final String name;
        switch (t.type) {
            case Comment:
                tb.insertCommentNode(t.asComment());
                break;
            case Doctype:
                tb.error(HtmlTreeBuilderState.InHead);
                return false;
            case StartTag:
                Token.StartTag start = t.asStartTag();
                name = start.normalName();
                if (name.equals("html")) {
                    return HtmlTreeBuilderState.InBody.process(t, tb);
                } else if (inSorted(name, InHeadEmpty)) {
                    Element el = tb.insertEmptyElementFor(start);
                    // jsoup special: update base the first time it is seen
                    if (name.equals("base") && el.hasAttr("href"))
                        tb.maybeSetBaseUri(el);
                } else if (name.equals("meta")) {
                    tb.insertEmptyElementFor(start);
                } else if (name.equals("title")) {
                    HtmlTreeBuilderStateHelper.HandleTextState(start, tb, tb.tagFor(start).textState());
                } else if (inSorted(name, InHeadRaw)) {
                    HtmlTreeBuilderStateHelper.HandleTextState(start, tb, tb.tagFor(start).textState());
                } else if (name.equals("noscript")) {
                    // else if noscript && scripting flag = true: rawtext (jsoup doesn't run script, to handle as noscript)
                    tb.insertElementFor(start);
                    tb.transition(HtmlTreeBuilderState.InHeadNoscript);
                } else if (name.equals("script")) {
                    // skips some script rules as won't execute them
                    tb.tokeniser.transition(TokeniserState.ScriptData);
                    tb.markInsertionMode();
                    tb.transition(HtmlTreeBuilderState.Text);
                    tb.insertElementFor(start);
                } else if (name.equals("head")) {
                    tb.error(HtmlTreeBuilderState.InHead);
                    return false;
                } else if (name.equals("template")) {
                    tb.insertElementFor(start);
                    tb.insertMarkerToFormattingElements();
                    tb.framesetOk(false);
                    tb.transition(HtmlTreeBuilderState.InTemplate);
                    tb.pushTemplateMode(HtmlTreeBuilderState.InTemplate);
                } else {
                    return anythingElseInHead(t, tb);
                }
                break;
            case EndTag:
                Token.EndTag end = t.asEndTag();
                name = end.normalName();
                if (name.equals("head")) {
                    tb.pop();
                    tb.transition(HtmlTreeBuilderState.AfterHead);
                } else if (inSorted(name, InHeadEnd)) {
                    return anythingElseInHead(t, tb);
                } else if (name.equals("template")) {
                    if (!tb.onStack(name)) {
                        tb.error(HtmlTreeBuilderState.InHead);
                    } else {
                        tb.generateImpliedEndTags(true);
                        if (!tb.currentElementIs(name)) tb.error(HtmlTreeBuilderState.InHead);
                        tb.popStackToClose(name);
                        tb.clearFormattingElementsToLastMarker();
                        tb.popTemplateMode();
                        tb.resetInsertionMode();
                    }
                }
                else {
                    tb.error(HtmlTreeBuilderState.InHead);
                    return false;
                }
                break;
            default:
                return anythingElseInHead(t, tb);
        }
        return true;
    }

    private static boolean anythingElseInHead(Token t, HtmlTreeBuilder tb) {
        tb.processEndTag("head");
        return tb.process(t);
    }

    public static boolean processInHeadNoscript(Token t, HtmlTreeBuilder tb) {
        if (t.isDoctype()) {
            tb.error(HtmlTreeBuilderState.InHeadNoscript);
            return false;
        } else if (t.isStartTag() && t.asStartTag().normalName().equals("html")) {
            return tb.process(t, HtmlTreeBuilderState.InBody);
        } else if (t.isEndTag() && t.asEndTag().normalName().equals("noscript")) {
            tb.pop();
            tb.transition(HtmlTreeBuilderState.InHead);
            return true;
        } else if (HtmlTreeBuilderStateHelper.isWhitespace(t) || t.isComment() || (t.isStartTag() && inSorted(t.asStartTag().normalName(),
                InHeadNoScriptHead))) {
            return tb.process(t, HtmlTreeBuilderState.InHead);
        } else if (t.isEndTag() && t.asEndTag().normalName().equals("br")) {
            return anythingElseInHeadNoscript(t, tb);
        } else if ((t.isStartTag() && inSorted(t.asStartTag().normalName(), InHeadNoscriptIgnore)) || t.isEndTag()) {
            tb.error(HtmlTreeBuilderState.InHeadNoscript);
            return false;
        } else {
            return anythingElseInHeadNoscript(t, tb);
        }
    }

    private static boolean anythingElseInHeadNoscript(Token t, HtmlTreeBuilder tb) {
        // note that this deviates from spec, which is to pop out of noscript and reprocess in head:
        // https://html.spec.whatwg.org/multipage/parsing.html#parsing-main-inheadnoscript
        // allows content to be inserted as data
        tb.error(HtmlTreeBuilderState.InHeadNoscript);
        tb.insertCharacterNode(new Token.Character().data(t.toString()));
        return true;
    }

    public static boolean processAfterHead(Token t, HtmlTreeBuilder tb) {
        if (HtmlTreeBuilderStateHelper.isWhitespace(t)) {
            tb.insertCharacterNode(t.asCharacter());
        } else if (t.isComment()) {
            tb.insertCommentNode(t.asComment());
        } else if (t.isDoctype()) {
            tb.error(HtmlTreeBuilderState.AfterHead);
        } else if (t.isStartTag()) {
            Token.StartTag startTag = t.asStartTag();
            String name = startTag.normalName();
            if (name.equals("html")) {
                return tb.process(t, HtmlTreeBuilderState.InBody);
            } else if (name.equals("body")) {
                tb.insertElementFor(startTag);
                tb.framesetOk(false);
                tb.transition(HtmlTreeBuilderState.InBody);
            } else if (name.equals("frameset")) {
                tb.insertElementFor(startTag);
                tb.transition(HtmlTreeBuilderState.InFrameset);
            } else if (inSorted(name, InBodyStartToHead)) {
                tb.error(HtmlTreeBuilderState.AfterHead);
                Element head = tb.getHeadElement();
                tb.push(head);
                tb.process(t, HtmlTreeBuilderState.InHead);
                tb.removeFromStack(head);
            } else if (name.equals("head")) {
                tb.error(HtmlTreeBuilderState.AfterHead);
                return false;
            } else {
                anythingElseAfterHead(t, tb);
            }
        } else if (t.isEndTag()) {
            String name = t.asEndTag().normalName();
            if (inSorted(name, AfterHeadBody)) {
                anythingElseAfterHead(t, tb);
            } else if (name.equals("template")) {
                tb.process(t, HtmlTreeBuilderState.InHead);
            }
            else {
                tb.error(HtmlTreeBuilderState.AfterHead);
                return false;
            }
        } else {
            anythingElseAfterHead(t, tb);
        }
        return true;
    }

    private static boolean anythingElseAfterHead(Token t, HtmlTreeBuilder tb) {
        tb.processStartTag("body");
        tb.framesetOk(true);
        return tb.process(t);
    }
}
